import { OrderRepository } from '../repositories/order.repository.js';
import { UserRepository } from '../repositories/user.repository.js';
import { Logger } from '../utils/logger.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricDetail,
  MetricSummary,
  MetricType,
  TimeGranularity,
  TimeSeries,
  TimeSeriesPoint,
  TopProduct,
} from '../models/analytics.js';

/**
 * Aggregation service that computes analytics from order and user data.
 *
 * ## Design notes for implementers
 *
 * This service is the single place where raw repository data is transformed
 * into analytics-ready structures.  Each public method corresponds to one API
 * route (see `src/routes/analytics.routes.ts`).
 *
 * ### Aggregation strategy
 * 1. **Read** — pull the minimal set of entities from repositories using
 *    date-range predicates.  Prefer `findAll(predicate)` with a date filter
 *    over fetching everything.
 * 2. **Bucket** — group entities into time-series buckets based on the
 *    requested `granularity`.  Use `resolveTimeRange()` to turn a `TimeRange`
 *    shortcut into concrete `{ start, end }` dates.
 * 3. **Reduce** — compute the aggregate value for each bucket (sum, count,
 *    average, etc.).
 * 4. **Compare** — for KPI summaries, repeat steps 1-3 for the *previous*
 *    equivalent period and compute the percentage change.
 *
 * ### Performance considerations
 * The in-memory database makes full scans cheap today.  If this moves to a
 * real datastore, consider:
 * - Pre-aggregated materialised views for dashboard summaries.
 * - Caching layer (TTL ~60 s) in front of `getDashboard()`.
 * - Streaming aggregation for time-series with many buckets.
 */
export class AnalyticsService {
  private readonly logger: Logger;

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {
    this.logger = new Logger('AnalyticsService');
  }

  // -------------------------------------------------------------------------
  // Public API — one method per route
  // -------------------------------------------------------------------------

  /**
   * Returns the full dashboard payload (summaries + sparklines + top products).
   *
   * Route: GET /api/analytics/dashboard
   */
  async getDashboard(query: AnalyticsQuery): Promise<DashboardData> {
    this.logger.info(`Computing dashboard for range=${query.timeRange}`);

    const { start, end } = resolveTimeRange(query);

    const summaries = await this.computeAllSummaries(start, end);
    const revenueTimeSeries = this.buildTimeSeries('revenue', 'Revenue', start, end, query);
    const orderTimeSeries = this.buildTimeSeries('order_count', 'Orders', start, end, query);
    const topProducts = this.computeTopProducts(start, end, 5);

    return {
      summaries,
      revenueTimeSeries,
      orderTimeSeries,
      topProducts,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Returns detailed data for a single metric type.
   *
   * Route: GET /api/analytics/metrics/:type
   */
  async getMetricDetail(metricType: MetricType, query: AnalyticsQuery): Promise<MetricDetail> {
    this.logger.info(`Computing metric detail for type=${metricType}, range=${query.timeRange}`);

    const { start, end } = resolveTimeRange(query);

    const summary = this.computeSummary(metricType, start, end);
    const timeSeries = this.buildTimeSeries(metricType, metricType, start, end, query);

    return {
      summary,
      timeSeries,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Returns top products by revenue for the given time range.
   *
   * Route: GET /api/analytics/top-products
   */
  async getTopProducts(query: AnalyticsQuery, limit: number = 10): Promise<TopProduct[]> {
    this.logger.info(`Computing top products, limit=${limit}, range=${query.timeRange}`);

    const { start, end } = resolveTimeRange(query);
    return this.computeTopProducts(start, end, limit);
  }

  // -------------------------------------------------------------------------
  // Private helpers
  // -------------------------------------------------------------------------

  /**
   * Compute KPI summaries for every metric type.
   */
  private async computeAllSummaries(start: Date, end: Date): Promise<MetricSummary[]> {
    const types: MetricType[] = ['orders', 'revenue', 'users', 'products'];
    return types.map((type) => this.computeSummary(type, start, end));
  }

  /**
   * Compute a single KPI summary with period-over-period comparison.
   */
  private computeSummary(metricType: MetricType, start: Date, end: Date): MetricSummary {
    const currentValue = this.computeMetricValue(metricType, start, end);

    const { start: prevStart, end: prevEnd } = previousPeriod(start, end);
    const previousValue = this.computeMetricValue(metricType, prevStart, prevEnd);

    let changePercent = 0;
    if (previousValue !== 0) {
      changePercent = ((currentValue - previousValue) / previousValue) * 100;
    } else if (currentValue > 0) {
      changePercent = 100;
    }

    let trend: 'up' | 'down' | 'flat' = 'flat';
    if (changePercent > 0) trend = 'up';
    else if (changePercent < 0) trend = 'down';

    return {
      metric: metricType,
      label: metricTypeLabel(metricType),
      currentValue,
      previousValue,
      changePercent: Math.round(changePercent * 100) / 100,
      trend,
    };
  }

  /**
   * Compute the raw numeric value for a given metric type within a date range.
   */
  private computeMetricValue(metricType: MetricType, start: Date, end: Date): number {
    switch (metricType) {
      case 'orders': {
        const orders = this.orderRepository.findByDateRange(start, end);
        return orders.length;
      }
      case 'revenue': {
        const orders = this.orderRepository.findByDateRange(start, end);
        return orders.reduce((sum, order) => sum + order.total, 0);
      }
      case 'users': {
        const users = this.userRepository.findByDateRange(start, end);
        return users.length;
      }
      case 'products': {
        const orders = this.orderRepository.findByDateRange(start, end);
        return orders.reduce(
          (sum, order) => sum + order.items.reduce((s, item) => s + item.quantity, 0),
          0,
        );
      }
    }
  }

  /**
   * Build a time series for a given metric over [start, end].
   */
  private buildTimeSeries(
    metric: string,
    label: string,
    start: Date,
    end: Date,
    query: AnalyticsQuery,
  ): TimeSeries {
    const granularity = query.granularity ?? defaultGranularity(start, end);
    const buckets = generateBuckets(start, end, granularity);

    const points: TimeSeriesPoint[] = buckets.map((bucketStart, i) => {
      const bucketEnd = i < buckets.length - 1 ? buckets[i + 1] : end;
      const value = this.computeBucketValue(metric, bucketStart, bucketEnd);
      return {
        timestamp: bucketStart.toISOString(),
        value,
      };
    });

    return {
      metric,
      label,
      points,
    };
  }

  /**
   * Compute the aggregate value for a single time-series bucket.
   */
  private computeBucketValue(metric: string, start: Date, end: Date): number {
    switch (metric) {
      case 'revenue': {
        const orders = this.orderRepository.findByDateRange(start, end);
        return orders.reduce((sum, order) => sum + order.total, 0);
      }
      case 'order_count':
      case 'orders': {
        return this.orderRepository.findByDateRange(start, end).length;
      }
      case 'users': {
        return this.userRepository.findByDateRange(start, end).length;
      }
      case 'products': {
        const orders = this.orderRepository.findByDateRange(start, end);
        return orders.reduce(
          (sum, order) => sum + order.items.reduce((s, item) => s + item.quantity, 0),
          0,
        );
      }
      default:
        return 0;
    }
  }

  /**
   * Compute the top N products by revenue within [start, end].
   */
  private computeTopProducts(start: Date, end: Date, limit: number): TopProduct[] {
    const orders = this.orderRepository.findByDateRange(start, end);

    const productMap = new Map<
      string,
      { name: string; totalQuantity: number; totalRevenue: number; orderIds: Set<string> }
    >();

    for (const order of orders) {
      for (const item of order.items) {
        const existing = productMap.get(item.productId);
        if (existing) {
          existing.totalQuantity += item.quantity;
          existing.totalRevenue += item.quantity * item.unitPrice;
          existing.orderIds.add(order.id);
        } else {
          productMap.set(item.productId, {
            name: item.name,
            totalQuantity: item.quantity,
            totalRevenue: item.quantity * item.unitPrice,
            orderIds: new Set([order.id]),
          });
        }
      }
    }

    const products: TopProduct[] = [];
    for (const [productId, data] of productMap) {
      products.push({
        productId,
        name: data.name,
        totalQuantity: data.totalQuantity,
        totalRevenue: Math.round(data.totalRevenue * 100) / 100,
        orderCount: data.orderIds.size,
      });
    }

    products.sort((a, b) => b.totalRevenue - a.totalRevenue);
    return products.slice(0, limit);
  }
}

// ---------------------------------------------------------------------------
// Pure utility functions
// ---------------------------------------------------------------------------

/** Resolve a `TimeRange` shortcut + optional custom dates into concrete dates. */
export function resolveTimeRange(query: AnalyticsQuery): { start: Date; end: Date } {
  const now = new Date();
  const end = new Date(now);

  switch (query.timeRange) {
    case '24h':
      return { start: new Date(now.getTime() - 24 * 60 * 60 * 1000), end };
    case '7d':
      return { start: new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000), end };
    case '30d':
      return { start: new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000), end };
    case '90d':
      return { start: new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000), end };
    case 'custom': {
      if (!query.startDate || !query.endDate) {
        throw new Error('startDate and endDate are required when timeRange is "custom"');
      }
      return { start: new Date(query.startDate), end: new Date(query.endDate) };
    }
  }
}

/** Compute the previous period of the same duration, ending where the current period starts. */
function previousPeriod(start: Date, end: Date): { start: Date; end: Date } {
  const durationMs = end.getTime() - start.getTime();
  return {
    start: new Date(start.getTime() - durationMs),
    end: new Date(start.getTime()),
  };
}

/** Pick a default granularity based on the range duration. */
function defaultGranularity(start: Date, end: Date): TimeGranularity {
  const durationMs = end.getTime() - start.getTime();
  const days = durationMs / (24 * 60 * 60 * 1000);

  if (days <= 2) return 'hour';
  if (days <= 31) return 'day';
  if (days <= 90) return 'week';
  return 'month';
}

/** Generate bucket start timestamps for the given range and granularity. */
function generateBuckets(start: Date, end: Date, granularity: TimeGranularity): Date[] {
  const buckets: Date[] = [];
  const current = new Date(start);

  while (current < end) {
    buckets.push(new Date(current));

    switch (granularity) {
      case 'hour':
        current.setTime(current.getTime() + 60 * 60 * 1000);
        break;
      case 'day':
        current.setDate(current.getDate() + 1);
        break;
      case 'week':
        current.setDate(current.getDate() + 7);
        break;
      case 'month':
        current.setMonth(current.getMonth() + 1);
        break;
    }
  }

  return buckets;
}

/** Map MetricType to a human-readable label. */
function metricTypeLabel(type: MetricType): string {
  const labels: Record<MetricType, string> = {
    orders: 'Total Orders',
    revenue: 'Total Revenue',
    users: 'Active Users',
    products: 'Products Sold',
  };
  return labels[type];
}

